import heapq
from collections import defaultdict

def solve(deps: dict[str, list[str]]) -> list[list[str]]:
    # 收集所有节点
    nodes = set(deps.keys())
    for preqs in deps.values():
        nodes.update(preqs)
    if not nodes:
        return []

    indeg = {node: 0 for node in nodes}
    graph = defaultdict(list)

    for task, preqs in deps.items():
        for p in preqs:
            graph[p].append(task)
            indeg[task] += 1

    heap = [node for node in nodes if indeg[node] == 0]
    heapq.heapify(heap)

    result = []
    while heap:
        layer = []
        while heap:
            node = heapq.heappop(heap)
            layer.append(node)
        result.append(layer)
        for node in layer:
            for neigh in graph[node]:
                indeg[neigh] -= 1
                if indeg[neigh] == 0:
                    heapq.heappush(heap, neigh)

    processed = sum(len(layer) for layer in result)
    if processed != len(nodes):
        return []
    return result
```

