def solve(base: dict, patch: dict) -> dict:
    result = {}
    for key in base:
        if key not in patch:
            result[key] = base[key]
        else:
            p = patch[key]
            if p is None:
                continue
            elif isinstance(base[key], dict) and isinstance(p, dict):
                result[key] = solve(base[key], p)
            else:
                result[key] = p
    for key in patch:
        if key not in base:
            p = patch[key]
            if p is not None:
                result[key] = p
    return result
