        if unit == 'd':
            total += num * 24 * 60 * 60 * 1000
        elif unit == 'h':
            total += num * 60 * 60 * 1000
        elif unit == 'm':
            total += num * 60 * 1000
        elif unit == 's':
            total += num * 1000
        elif unit == 'ms':
