def solve(s: str) -> bool:
    stack = []
    matching = {')': '(', ']': '[', '}': '{'}
    in_string = False
    string_char = None
    i = 0
    n = len(s)
    while i < n:
        ch = s[i]
        if in_string:
            if ch == '\\' and i + 1 < n:
                i += 2
                continue
            if ch == string_char:
                in_string = False
                string_char = None
            i += 1
            continue
        if ch in ('"', "'"):
            in_string = True
            string_char = ch
            i += 1
            continue
        if ch in '([{':
            stack.append(ch)
        elif ch in ')]}':
            if not stack or stack[-1] != matching[ch]:
                return False
            stack.pop()
        i += 1
    return not stack
```

