def solve(tree: dict) -> list[str]:
    result = []
    def dfs(subtree, prefix):
        for key in sorted(subtree.keys()):
            val = subtree[key]
            new_prefix = f"{prefix}.{key}" if prefix else key
            if isinstance(val, dict):
                dfs(val, new_prefix)
            else:
                result.append(f"{new_prefix}={val}")
    dfs(tree, "")
    return sorted(result)

